   135	bool is_csi_rs_in_symbol(const fapi_nr_dl_config_csirs_pdu_rel15_t csirs_config_pdu, const int symbol) {
   136	
   137	  bool ret = false;
   138	
   139	  // 38.211-Table 7.4.1.5.3-1: CSI-RS locations within a slot
   140	  switch(csirs_config_pdu.row){
   141	    case 1:
   142	    case 2:
   143	    case 3:
   144	    case 4:
   145	    case 6:
   146	    case 9:
   147	      if(symbol == csirs_config_pdu.symb_l0) {
   148	        ret = true;
   149	      }
   150	      break;
   151	    case 5:
   152	    case 7:
   153	    case 8:
   154	    case 10:
   155	    case 11:
   156	    case 12:
   157	      if(symbol == csirs_config_pdu.symb_l0 || symbol == (csirs_config_pdu.symb_l0+1) ) {
   158	        ret = true;
   159	      }
   160	      break;
   161	    case 13:
   162	    case 14:
   163	    case 16:
   164	    case 17:
   165	      if(symbol == csirs_config_pdu.symb_l0 || symbol == (csirs_config_pdu.symb_l0+1) ||
   166	          symbol == csirs_config_pdu.symb_l1 || symbol == (csirs_config_pdu.symb_l1+1)) {
   167	        ret = true;
   168	      }
   169	      break;
   170	    case 15:
   171	    case 18:
   172	      if(symbol == csirs_config_pdu.symb_l0 || symbol == (csirs_config_pdu.symb_l0+1) || symbol == (csirs_config_pdu.symb_l0+2) ) {
   173	        ret = true;
   174	      }
   175	      break;
   176	    default:
   177	      AssertFatal(0==1, "Row %d is not valid for CSI Table 7.4.1.5.3-1\n", csirs_config_pdu.row);
   178	  }
   179	
   180	  return ret;
   181	}
