                                csi_rs_estimated_channel_freq,
                                noise_power,
                                log2_re,
                                &sl_sinr_dB);

    // bit 4 in bitmap to indicate RI measurment
    if (csirs_config_pdu->measurement_bitmap & 16) {
      if (get_softmodem_params()->sl_mode == 2) {
        nr_csi_rs_cqi_estimation_sl(sl_sinr_dB, &cqi);
